import type { CittyPlugin, Resolvable } from "./types.ts";
import { resolveValue } from "./_utils.ts";

export function defineCittyPlugin(plugin: Resolvable<CittyPlugin>): Resolvable<CittyPlugin> {
  return plugin;
}

