describe("usage", () => {
  it("renders arguments", async () => {
    const command = defineCommand({
      meta: {
        name: "Commander",
        description: "A command",
      },
      args: {
        foo: {
          type: "string",
          required: true,
          description: "A foo",
        },
        bar: {
          alias: ["b"],
          type: "string",
          description: "A bar",
        },
        pos: {
          type: "positional",
          name: "pos",
          description: "A pos",
        },
        enum: {
          type: "enum",
          name: "enum",
          options: ["a", "b"],
          description: "An enum",
        },
        boolean: {
          type: "boolean",
          name: "boolean",
          description: "A boolean",
        },
      },
    });

    const usage = await renderUsage(command);

    expect(usage).toMatchInlineSnapshot(`
      "A command (Commander)

      USAGE Commander [OPTIONS] --foo=<foo> <POS>

      ARGUMENTS

        POS    A pos (Required)

      OPTIONS

            --foo=<foo>    A foo (Required)
        -b, --bar=<bar>    A bar           
           --enum=<a|b>    An enum         
              --boolean    A boolean       
